import React, { useState } from "react";
import axios from "axios";
import "./App.css";
import IndividualAnalysis from "./IndividualAnalysis";
import BatchAnalysis from "./BatchAnalysis";

const API_BASE = "http://localhost:5000/api";

function App() {
  const [mode, setMode] = useState("individual");
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchFile, setBatchFile] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: "Mobile Phone",
    PreferredPaymentMode: "Credit Card",
    PreferedOrderCat: "Laptop & Accessory",
    Gender: "Male",
    MaritalStatus: "Married",
  });

  const handleIndividualAnalyze = async () => {
    setLoading(true);
    try {
      const res = await axios.post(`${API_BASE}/individual`, customerData);
      setResults(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleBatchAnalyze = async () => {
    if (!batchFile) return;
    setLoading(true);
    const formData = new FormData();
    formData.append("file", batchFile);
    try {
      const res = await axios.post(`${API_BASE}/batch`, formData);
      setBatchResults(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-wrapper">
      {/* NAVBAR */}
      <header className="nav-header">
        <div className="nav-left">
          <h2 className="nav-logo">
            Churn<span>Intel</span>
          </h2>
        </div>

        <div className="nav-center">
          <button
            className={`nav-link ${mode === "individual" ? "active" : ""}`}
            onClick={() => setMode("individual")}
          >
            Individual
          </button>
          <button
            className={`nav-link ${mode === "batch" ? "active" : ""}`}
            onClick={() => setMode("batch")}
          >
            Batch
          </button>
        </div>

        <div className="nav-right">
          <button className="nav-btn">Docs</button>
          <button className="nav-btn secondary">Support</button>
        </div>
      </header>

      {/* DYNAMIC HEADER */}
      <section
        className={`hero ${
          mode === "individual" ? "individual-mode" : "batch-mode"
        }`}
      >
        <h1 key={mode} className="fade-title">
          {mode === "individual" ? "Individual Analysis" : "Batch Analysis"}
        </h1>
        <p>
          {mode === "individual"
            ? "Analyze a single customer’s churn probability with detailed insights."
            : "Upload and evaluate multiple customer records at once for batch churn prediction."}
        </p>
      </section>

      {/* MAIN CONTENT */}
      <main className="dashboard">
        <div className="card">
          {mode === "individual" ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={setCustomerData}
              onAnalyze={handleIndividualAnalyze}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalyze}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
